import{_ as a,o as t,c as s,a2 as o}from"./chunks/framework.DGS7qFRZ.js";const u=JSON.parse('{"title":"Authentication","description":"","frontmatter":{},"headers":[],"relativePath":"auth.md","filePath":"auth.md","lastUpdated":1782037448000}'),i={name:"auth.md"};function n(l,e,r,c,d,h){return t(),s("div",null,[...e[0]||(e[0]=[o(`<h1 id="authentication" tabindex="-1">Authentication <a class="header-anchor" href="#authentication" aria-label="Permalink to &quot;Authentication&quot;">​</a></h1><p>The CLI authenticates to the Google Play Developer API via a service account. This doc covers how to create one, what roles it needs, and how to plumb it into the config.</p><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 1. Create a service account on Google Cloud + grant it Play Console access (see below)</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 2. Download the JSON key to .secret-stuff/</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 3. Write .secret-stuff/playstore-config.yaml:</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#    package_name: &quot;com.your.app&quot;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#    service_account_key: &quot;play-service-account.json&quot;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 4. Smoke-test:</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">playstore</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> info</span></span></code></pre></div><h2 id="creating-a-service-account" tabindex="-1">Creating a service account <a class="header-anchor" href="#creating-a-service-account" aria-label="Permalink to &quot;Creating a service account&quot;">​</a></h2><p>The setup has <strong>two halves</strong> — Google Cloud (where the service account lives) and Play Console (where you grant it the right roles).</p><h3 id="half-1-google-cloud" tabindex="-1">Half 1: Google Cloud <a class="header-anchor" href="#half-1-google-cloud" aria-label="Permalink to &quot;Half 1: Google Cloud&quot;">​</a></h3><ol><li><a href="https://console.cloud.google.com/" target="_blank" rel="noreferrer">console.cloud.google.com</a> → pick or create a project.</li><li><strong>IAM &amp; Admin → Service Accounts → Create Service Account</strong>.</li><li>Name it something obvious (<code>play-publisher</code>, <code>play-cli-readonly</code>, etc.).</li><li><strong>Don&#39;t grant any GCP roles here</strong> — Play access is granted in Play Console, not GCP IAM.</li><li>After creating, click the account → <strong>Keys → Add Key → Create new key → JSON</strong>.</li><li>Save the downloaded JSON to your repo&#39;s <code>.secret-stuff/</code>.</li></ol><h3 id="half-2-play-console" tabindex="-1">Half 2: Play Console <a class="header-anchor" href="#half-2-play-console" aria-label="Permalink to &quot;Half 2: Play Console&quot;">​</a></h3><ol><li><a href="https://play.google.com/console/" target="_blank" rel="noreferrer">play.google.com/console</a> → <strong>Users and permissions → Invite new users</strong>.</li><li>Email is the service account&#39;s email (looks like <code>play-publisher@your-project.iam.gserviceaccount.com</code>).</li><li><strong>App access</strong>: pick the app(s) this service account should manage.</li><li><strong>Account permissions</strong> + <strong>App permissions</strong>: see roles below.</li><li>Save. Propagation takes a few minutes.</li></ol><h2 id="required-roles" tabindex="-1">Required roles <a class="header-anchor" href="#required-roles" aria-label="Permalink to &quot;Required roles&quot;">​</a></h2><p>For the operations the CLI supports, you want <strong>at minimum</strong>:</p><table tabindex="0"><thead><tr><th>Permission</th><th>Why</th></tr></thead><tbody><tr><td><strong>View app information and download bulk reports</strong></td><td>Required for almost every read</td></tr><tr><td><strong>Edit store listing, pricing &amp; distribution</strong></td><td><code>listings update</code>, <code>iap sync</code>, <code>iap migrate-prices</code></td></tr><tr><td><strong>Manage store presence</strong></td><td>Custom store listings, store-listing experiments</td></tr><tr><td><strong>Manage production releases</strong> + <strong>Manage testing tracks</strong></td><td><code>tracks</code> commands</td></tr></tbody></table><p>For read-only setups (CI checks, dashboards), the <strong>View app information</strong> role on its own is enough for <code>playstore info</code>, <code>iap list</code>, <code>iap show</code>, <code>iap diff</code>, <code>listings show</code>.</p><p>For pushes, you want <code>Edit store listing</code> + <code>Manage releases</code> per app you&#39;re managing.</p><h2 id="multiple-service-accounts" tabindex="-1">Multiple service accounts <a class="header-anchor" href="#multiple-service-accounts" aria-label="Permalink to &quot;Multiple service accounts&quot;">​</a></h2><p>You can configure multiple keys, though playstore-cli&#39;s config format is simpler than appstore-cli&#39;s — one <code>service_account_key</code> per config file. To use multiple, either:</p><ul><li>Run with <code>--key-file &lt;path&gt;</code> to override per call.</li><li>Set <code>GOOGLE_PLAY_KEY_FILE</code> env var for the shell.</li></ul><p>Or maintain multiple worktrees with different configs if you have a strong separation between read-only and read-write keys.</p><h2 id="auth-lifecycle" tabindex="-1">Auth lifecycle <a class="header-anchor" href="#auth-lifecycle" aria-label="Permalink to &quot;Auth lifecycle&quot;">​</a></h2><p>The CLI uses the <code>googleapis</code> library, which handles OAuth2 token exchange automatically:</p><ol><li>Reads the JSON key.</li><li>Signs a JWT assertion (<code>iss</code>, <code>scope</code>, <code>aud</code>, <code>exp</code>).</li><li>Exchanges the JWT for an OAuth2 access token via Google&#39;s token endpoint.</li><li>Caches the access token for ~1 hour (Google&#39;s default).</li></ol><p>You don&#39;t manage tokens — they refresh automatically as needed. The JSON key never leaves your machine.</p><h2 id="service-account-rotation" tabindex="-1">Service-account rotation <a class="header-anchor" href="#service-account-rotation" aria-label="Permalink to &quot;Service-account rotation&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 1. Create a NEW JSON key on Google Cloud (keep the old one active)</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 2. Drop the new JSON in .secret-stuff/</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 3. Smoke with --key-file &lt;new-json&gt;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">playstore</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> info</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --key-file</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .secret-stuff/play-new.json</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 4. Once you&#39;ve confirmed it works, swap service_account_key in playstore-config.yaml</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 5. Delete the old key on Google Cloud</span></span></code></pre></div><p>If you&#39;re paranoid about Play API access during rotation, the old key keeps working until you delete it; there&#39;s no atomic-swap required.</p><h2 id="validating-auth" tabindex="-1">Validating auth <a class="header-anchor" href="#validating-auth" aria-label="Permalink to &quot;Validating auth&quot;">​</a></h2><p>The cheapest read is <code>playstore info</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">playstore</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> info</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># {</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#   &quot;packageName&quot;: &quot;com.your.app&quot;,</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#   &quot;defaultLanguage&quot;: &quot;en-GB&quot;,</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#   &quot;contactWebsite&quot;: &quot;https://your.app&quot;,</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#   ...</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># }</span></span></code></pre></div><p>If you see <code>403 Forbidden</code>, the service account doesn&#39;t have Play Console access for that app — go back to Play Console → Users and permissions and add it.</p><p>If you see <code>401 Unauthorized</code> or <code>invalid_grant</code>, the JSON key is wrong (typo in path, corrupted file, or revoked on GCP).</p><h2 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h2><ul><li><strong>Never commit <code>play-service-account.json</code> or <code>playstore-config.yaml</code>.</strong> Verify <code>.secret-stuff/</code> is in your <code>.gitignore</code> before your first commit.</li><li>The JSON private key is stored on disk only; the CLI loads it on each run, exchanges it for an access token, and caches the access token in-process for the request lifetime.</li><li>Service accounts can be revoked in either GCP IAM (kills the JWT signing) or Play Console (kills the app access). Use both during rotation for defence in depth.</li></ul><h2 id="env-var-overrides" tabindex="-1">Env-var overrides <a class="header-anchor" href="#env-var-overrides" aria-label="Permalink to &quot;Env-var overrides&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Var</th><th>Effect</th></tr></thead><tbody><tr><td><code>GOOGLE_PLAY_KEY_FILE</code></td><td>Use this JSON path instead of the config&#39;s <code>service_account_key</code></td></tr><tr><td><code>PLAYSTORE_SECRETS_DIR</code></td><td>Where to look for <code>playstore-config.yaml</code> + JSON</td></tr><tr><td><code>PLAYSTORE_METADATA_DIR</code></td><td>Override where <code>iap.yaml</code> lives</td></tr><tr><td><code>PLAYSTORE_LISTINGS_DIR</code></td><td>Override where listings + screenshots + release notes live</td></tr></tbody></table>`,35)])])}const g=a(i,[["render",n]]);export{u as __pageData,g as default};
